<?php
// PHP Based File Restorer/Updater
$files = [
    'index.php' => base64_decode(''),
    'includes/header.php' => base64_decode(''),
    'includes/footer.php' => base64_decode(''),
    'assets/css/style.css' => base64_decode('')
];

foreach ($files as $path => $content) {
    $fullPath = __DIR__ . '/../' . $path;
    echo "Updating $path... ";
    if (file_put_contents($fullPath, $content)) {
        echo "SUCCESS<br>";
    } else {
        echo "FAILED (Check permissions)<br>";
    }
}
?>
